def solve(n: Long, edges: Array[Array[Long]]): Long = {
  val adj = Array.fill(n.toInt)(mutable.ListBuffer.empty[(Int, Long)])
  val reverseEdges = Array.fill(n.toInt)(mutable.ListBuffer.empty[(Int, Long)])

  for (e <- edges) {
    val u = e(0).toInt
    val v = e(1).toInt
    val w = e(2)
    adj(u) += ((v, w))
    reverseEdges(v) += ((u, w))
  }

  val heap = mutable.PriorityQueue.empty[(Long, Int, Boolean)](
    Ordering.by[(Long, Int, Boolean), Long](_._1).reverse
  )
  heap.enqueue((0L, 0, false))

  val dist = mutable.Map.empty[(Int, Boolean), Long]
  dist((0, false)) = 0L

  while (heap.nonEmpty) {
    val (currentCost, u, usedFlip) = heap.dequeue()
    if (u == n - 1) {
      return currentCost
